scwin.getMaxCloseYm = function() {
    console.log("=== getMaxCloseYm (전월 마감여부)");
//	tr_getMaxCloseYm.Post();

    // ds_search2.AddRow();
    // ds_search2.NameValue(1,"coCd") = vCoCd;
