//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function (strCd,strNm,rtnList, flag){
    console.log("=== f_resultPopEd (팝업결과)");

	if (rtnList != null ) {
		if (rtnList[0] == "N/A") {
            // 히든값 분기처리
            switch (flag){
                case '1'  : scwin.ed_slipKndCd_hidVal      = ""; break;  // 전표종류
                case '2'  : scwin.ed_slipAcctDeptCd_hidVal = ""; break;  // 전표귀속부서
                case '3'  : scwin.ed_drawEmpNo_hidVal      = ""; break;  // 작성자
                default  : break;
            }
			return;
		}
		// strCd.Text = rtnList[0];	// 코드
		// strNm.value = rtnList[1];	// 명
        // strCd.hidVal = rtnList[0];  // 히든값

		strCd.setValue(rtnList[0]);	// 코드
		strNm.setValue(rtnList[1]);	// 명

        // 히든값 분기처리
        switch (flag){
            case '1'  : scwin.ed_slipKndCd_hidVal      = rtnList[0]; break;  // 전표종류
            case '2'  : scwin.ed_slipAcctDeptCd_hidVal = rtnList[0]; break;  // 전표귀속부서
            case '3'  : scwin.ed_drawEmpNo_hidVal      = rtnList[0]; break;  // 작성자
            default   : break;
        }
	}else{
		// strCd.Text = "";
		// strNm.value = "";
		// strCd.hidVal = "";
	    strCd.setValue( "" );
		strNm.setValue( "" );

        // 히든값 분기처리
        switch (flag){
            case '1'  : scwin.ed_slipKndCd_hidVal      = ""; break;  // 전표종류
            case '2'  : scwin.ed_slipAcctDeptCd_hidVal = ""; break;  // 전표귀속부서
            case '3'  : scwin.ed_drawEmpNo_hidVal      = ""; break;  // 작성자
            default  : break;
        }
	}
};

//-------------------------------------------------------------------------
// 팝업체크 - 코드값 변경시 자동검색
//   flag : 팝업 플래그
//-------------------------------------------------------------------------
//   1:전표종류,2:귀속부서,3:작성자
scwin.f_checkPopEd = function(strCd,strNm,flag) {
    console.log("===== f_checkPopEd (팝업체크 - 코드값 변경시 자동검색)  srtCd["+strCd.getValue()+"] strNm["+strNm.getValue()+"] flag["+flag+"]");

	// if (strCd.text.trim() == strCd.hidVal)
    //     return;

    if ( ( flag=='1'  && (strCd.getValue().trim() == scwin.ed_slipKndCd_hidVal      )) ||  // 전표종류
         ( flag=='2'  && (strCd.getValue().trim() == scwin.ed_slipAcctDeptCd_hidVal )) ||  // 전표귀속부서
         ( flag=='3'  && (strCd.getValue().trim() == scwin.ed_drawEmpNo_hidVal      ))     // 작성자
        ) {
        // KYU_TEST : 히든 비교시 코드가 null 이 아니어야 함. (코드 null 일 때 명 null 처리)
        if ( strCd.getValue() != "" ) return;
    }

	//  strNm.value="";

    // 명 초기화
    switch (flag){
        case '1'  : ed_slipKndNm.setValue("");      break;  // 전표종류
        case '2'  : ed_slipAcctDeptNm.setValue(""); break;  // 전표귀속부서
        case '2'  : ed_drawEmpNm.setValue("");      break;  // 작성자
        default   : break;
    }

	//  strCd.hidVal = "";

    // 히든값 초기화
    switch (flag){
		case '1'  : scwin.ed_slipKndCd_hidVal      = ""; break;  // 전표종류
		case '2'  : scwin.ed_slipAcctDeptCd_hidVal = ""; break;  // 전표귀속부서
        case '2'  : scwin.ed_drawEmpNo_hidVal      = ""; break;  // 작성자
        default   : break;
    }

	// if(strCd.text.trim()!="") f_openPopUp(flag,'T');

	if(strCd.getValue().trim()!="") {

        // 팝업 로딩
        switch (flag){
		    case '1'  : scwin.f_openPopUp(flag,'T'); break;  // 전표종류
		    case '2'  : scwin.f_openPopUp(flag,'T'); break;  // 전표귀속부서
            case '3'  : scwin.f_openPopUp(flag,'T'); break;  // 작성자
            default   : break;
        }
    }
};


